// Analyze repository content
const content = repo_content || ''
const lines = content.split('\n')
const tsFiles = lines.filter(line => line.includes('.ts')).length
const jsFiles = lines.filter(line => line.includes('.js')).length

// Extract key metrics
const metrics = {
  total_lines: lines.length,
  typescript_files: tsFiles,
  javascript_files: jsFiles,
  has_readme: content.toLowerCase().includes('readme'),
  content_size: content.length,
  analysis_timestamp: new Date().toISOString()
}

return {
  repository: _record.metadata.repository,
  owner: _record.metadata.owner,
  metrics: metrics,
  summary: `Found ${tsFiles + jsFiles} source files (${tsFiles} TS, ${jsFiles} JS) in ${lines.length} total lines`
}

