// Custom itinerary generation logic
const { destination, duration_days, interests, budget } = params;

const activities = {
  food: ['Visit local markets', 'Food tour', 'Cooking class'],
  technology: ['Tech museum', 'Innovation center', 'Electronics district'],
  culture: ['Historic temples', 'Traditional performances', 'Art galleries']
};

const itinerary = [];
for (let day = 1; day <= duration_days; day++) {
  const dayActivities = interests.flatMap(interest => activities[interest] || []).slice(0, 3);
  itinerary.push({
    day: day,
    activities: dayActivities,
    meals: ['Breakfast', 'Lunch', 'Dinner'],
    budget_estimate: budget === 'moderate' ? '$100-150' : budget === 'expensive' ? '$200+' : '$50-80'
  });
}

return {
  destination,
  total_days: duration_days,
  daily_plans: itinerary,
  estimated_total_cost: budget === 'moderate' ? `$${duration_days * 125}` : budget === 'expensive' ? `$${duration_days * 250}` : `$${duration_days * 65}`
};

const { weather, restaurants, itinerary, destination } = params;

return {
  destination,
  summary: {
    weather_conditions: weather || 'Weather information pending',
    dining_options: restaurants || 'Restaurant recommendations pending',
    daily_itinerary: itinerary || 'Itinerary pending',
    booking_status: 'Ready for confirmation'
  },
  next_steps: [
    'Review weather forecast',
    'Make restaurant reservations',
    'Book activities in advance',
    'Arrange transportation'
  ],
  created_at: new Date().toISOString()
};

import json
import statistics

# Use sample_data parameter if provided, otherwise use default sample data
if 'sample_data' not in dir() or not sample_data:
    sample_data = [
        {'revenue': 50000, 'units_sold': 500, 'profit_margin': 0.25},
        {'revenue': 75000, 'units_sold': 750, 'profit_margin': 0.30},
        {'revenue': 60000, 'units_sold': 600, 'profit_margin': 0.28},
        {'revenue': 90000, 'units_sold': 900, 'profit_margin': 0.32},
        {'revenue': 80000, 'units_sold': 800, 'profit_margin': 0.29}
    ]

# Calculate statistics for each metric
results = {
    'dataset': dataset_name,
    'metrics_analyzed': metrics,
    'statistics': {},
    'total_records': len(sample_data)
}

for metric in metrics:
    values = [item[metric] for item in sample_data if metric in item]
    if values:
        results['statistics'][metric] = {
            'mean': round(statistics.mean(values), 2),
            'median': round(statistics.median(values), 2),
            'stdev': round(statistics.stdev(values), 2) if len(values) > 1 else 0,
            'min': values[0] if len(values) == 1 else min(values),
            'max': values[0] if len(values) == 1 else max(values),
            'total': round(sum(values), 2) if isinstance(values[0], (int, float)) else len(values)
        }

# Calculate correlations (simplified)
if 'revenue' in results['statistics'] and 'units_sold' in results['statistics']:
    results['insights'] = {
        'avg_revenue_per_unit': round(results['statistics']['revenue']['mean'] / results['statistics']['units_sold']['mean'], 2),
        'revenue_volatility_percent': round((results['statistics']['revenue']['stdev'] / results['statistics']['revenue']['mean']) * 100, 2)
    }

print(json.dumps(results, indent=2))

interface ChartDataPoint {
  label: string;
  value: number;
}

interface ChartConfig {
  type: string;
  data: {
    labels: string[];
    datasets: Array<{
      label: string;
      data: number[];
      backgroundColor?: string[];
      borderColor?: string;
      borderWidth?: number;
    }>;
  };
  options: {
    responsive: boolean;
    plugins: {
      title: {
        display: boolean;
        text: string;
      };
      legend: {
        display: boolean;
      };
    };
  };
}

// Extract labels and values from data points
const labels = data_points.map((dp: ChartDataPoint) => dp.label);
const values = data_points.map((dp: ChartDataPoint) => dp.value);

// Generate color palette
const colors = [
  'rgba(255, 99, 132, 0.8)',
  'rgba(54, 162, 235, 0.8)',
  'rgba(255, 206, 86, 0.8)',
  'rgba(75, 192, 192, 0.8)',
  'rgba(153, 102, 255, 0.8)'
];

// Build Chart.js configuration
const config: ChartConfig = {
  type: chart_type,
  data: {
    labels: labels,
    datasets: [{
      label: title,
      data: values,
      backgroundColor: colors.slice(0, values.length),
      borderColor: 'rgba(0, 0, 0, 0.1)',
      borderWidth: 1
    }]
  },
  options: {
    responsive: true,
    plugins: {
      title: {
        display: true,
        text: title
      },
      legend: {
        display: chart_type === 'pie' || chart_type === 'radar'
      }
    }
  }
};

console.log(JSON.stringify(config, null, 2));

